/**
 * Prepare for MongoDB - n8n Code Node
 * - Requires each merged item to have an 'endpoint' field (set by Set node or HTTP node)
 * - Fallbacks to nodeMap if not present
 * - Handles price, candlestick, and funding data formats
 * - Enhanced funding data handling with optimized symbol matching
 * - Filters funding data to only keep the relevant entry for the queried symbol
 */

// Helper: Extract symbol from data, fallback to inputSymbol or 'UNKNOWN'
function extractSymbol(data, inputSymbol, endpoint) {
  // Direct symbol property
  if (data.symbol) return data.symbol;

  // For funding data which might have data.data[0].symbol format
  if (endpoint === 'funding' && data.data && Array.isArray(data.data) && data.data.length > 0) {
    // Always prioritize the inputSymbol if provided
    if (inputSymbol && inputSymbol !== 'UNKNOWN') {
      return inputSymbol;
    }

    // If no inputSymbol provided, use the first entry
    const fundingSymbol = data.data[0].symbol;
    if (fundingSymbol) {
      // Normalize symbol format (e.g., BTC_USDT -> BTCUSDT)
      return fundingSymbol.replace(/_([A-Z0-9]+)$/i, '$1');
    }
  }

  // For array data with objects containing symbol
  if (Array.isArray(data) && data[0] && typeof data[0] === 'object' && data[0].symbol) {
    return data[0].symbol;
  }

  return inputSymbol || 'UNKNOWN';
}

// Helper: Extract endpoint from data or fallback to nodeMap
function extractEndpoint(item, nodeMap, idx) {
  // First check json.endpoint which is most specific
  if (item.json && item.json.endpoint) return item.json.endpoint;

  // Then check item.endpoint (might be set by Edit node)
  if (item.endpoint) return item.endpoint;

  // Check if this is funding data by structure
  if (item.json && item.json.data && Array.isArray(item.json.data) && 
      item.json.data.length > 0 && item.json.data[0].fundingRate !== undefined) {
    return 'funding';
  }

  // Fall back to nodeMap based on position
  if (nodeMap && nodeMap[idx]) return nodeMap[idx];

  return 'unknown';
}

// Data processors for each endpoint type
const dataProcessors = {
  // Process candlestick data
  candlestick: (data, symbol) => {
    if (!Array.isArray(data.data)) return data;

    return {
      openTime: data.data[0],
      open: data.data[1],
      high: data.data[2],
      low: data.data[3],
      close: data.data[4],
      volume: data.data[5],
      closeTime: data.data[6],
      quoteAssetVolume: data.data[7]
    };
  },

  // Process price data
  price: (data, symbol) => {
    return data.price ? { price: data.price } : data;
  },

  // Process contract details data
  'contract-details': (data, symbol) => {
    // Extract contract details from the appropriate data structure
    const contractData = (data.success && data.data) ? data.data : 
                        (data.data && data.data.symbol) ? data.data : null;

    if (!contractData) return data;

    // Return only the essential contract details
    return {
      symbol: contractData.symbol,
      displayName: contractData.displayName,
      displayNameEn: contractData.displayNameEn,
      baseCoin: contractData.baseCoin,
      quoteCoin: contractData.quoteCoin,
      contractSize: contractData.contractSize,
      minLeverage: contractData.minLeverage,
      maxLeverage: contractData.maxLeverage,
      priceScale: contractData.priceScale,
      minVol: contractData.minVol,
      maxVol: contractData.maxVol,
      takerFeeRate: contractData.takerFeeRate,
      makerFeeRate: contractData.makerFeeRate,
      maintenanceMarginRate: contractData.maintenanceMarginRate,
      initialMarginRate: contractData.initialMarginRate,
      liquidationFeeRate: contractData.liquidationFeeRate,
      riskLimitCustom: contractData.riskLimitCustom
    };
  },

  // Process funding data
  funding: (data, symbol) => {
    if (!data.data || !Array.isArray(data.data)) return data;

    // Find the matching funding data entry
    const targetSymbolData = findMatchingFundingData(data.data, symbol);

    if (targetSymbolData) {
      return {
        fundingRate: targetSymbolData.fundingRate,
        maxFundingRate: targetSymbolData.maxFundingRate,
        minFundingRate: targetSymbolData.minFundingRate,
        collectCycle: targetSymbolData.collectCycle,
        nextSettleTime: targetSymbolData.nextSettleTime,
        timestamp: targetSymbolData.timestamp,
        originalSymbol: targetSymbolData.symbol,
        matchType: 'exact'
      };
    } else {
      return {
        fundingRate: null,
        maxFundingRate: null,
        minFundingRate: null,
        noMatchFound: true,
        queriedSymbol: symbol,
        availableSymbols: data.data.slice(0, 3).map(item => item.symbol || 'unknown')
      };
    }
  },

  // Process historical funding data
  'historical-funding': (data, symbol) => {
    if (!data.data) return data;

    // If data is an array of historical funding entries
    if (Array.isArray(data.data)) {
      // Filter entries for the specific symbol if possible
      const relevantEntries = data.data.filter(entry => {
        if (!entry.symbol) return false;

        // Try different symbol formats for matching
        const entrySymbol = entry.symbol.toUpperCase();
        const normalizedSymbol = symbol.toUpperCase();
        const symbolWithoutQuote = normalizedSymbol.replace(/USDT$|USD$/i, '');

        return entrySymbol.includes(symbolWithoutQuote) || 
               entrySymbol.replace(/_/g, '').includes(symbolWithoutQuote);
      });

      // Return filtered entries or original data if no matches
      return relevantEntries.length > 0 ? { 
        entries: relevantEntries,
        count: relevantEntries.length,
        originalSymbol: symbol
      } : data;
    }

    return data;
  },

  // Process orderbook data
  orderbook: (data, symbol) => {
    // Check if data has the expected orderbook structure
    if (!data.bids || !data.asks) return data;

    // Return a clean orderbook structure
    return {
      bids: data.bids,
      asks: data.asks,
      timestamp: data.timestamp || Date.now(),
      lastUpdateId: data.lastUpdateId
    };
  },

  // Process trades data
  trades: (data, symbol) => {
    // If data is an array of trades
    if (Array.isArray(data)) {
      // Return the trades with a count
      return {
        trades: data,
        count: data.length,
        timestamp: Date.now()
      };
    }

    // If data has a trades property that is an array
    if (data.trades && Array.isArray(data.trades)) {
      return {
        trades: data.trades,
        count: data.trades.length,
        timestamp: data.timestamp || Date.now()
      };
    }

    return data;
  }
};

// Helper: Find matching funding data entry
function findMatchingFundingData(fundingDataArray, symbol) {
  // Normalize symbol formats for matching
  const normalizedSymbol = symbol.toUpperCase();
  const symbolWithoutQuote = normalizedSymbol.replace(/USDT$|USD$/i, '');
  const underscoreFormat = symbolWithoutQuote + '_' + (normalizedSymbol.includes('USDT') ? 'USDT' : 'USD');

  // Try multiple matching strategies in order of precision
  let match = fundingDataArray.find(item => 
    item.symbol && item.symbol.toUpperCase() === underscoreFormat
  );

  // Match by coin part if direct match fails
  if (!match) {
    match = fundingDataArray.find(item => {
      if (!item.symbol) return false;
      const itemCoin = item.symbol.split('_')[0].toUpperCase();
      return itemCoin === symbolWithoutQuote;
    });
  }

  // Fuzzy match as last resort
  if (!match && symbolWithoutQuote.length >= 2) {
    match = fundingDataArray.find(item => {
      if (!item.symbol) return false;
      return item.symbol.toUpperCase().startsWith(symbolWithoutQuote);
    });
  }

  return match;
}

// Normalize symbol format (e.g., SOL_USDT -> SOLUSDT)
function normalizeSymbol(symbol) {
  return symbol.replace(/_/g, '');
}

// Main: Prepare MongoDB records
function prepareMongoRecords(items, inputSymbol, nodeMap) {
  let lastEndpoint = 'unknown';

  return items.map((item, idx) => {
    const json = item.json || {};

    // Extract endpoint
    let endpoint = extractEndpoint(item, nodeMap, idx) || json.endpoint || lastEndpoint;
    if (endpoint && endpoint !== 'unknown') lastEndpoint = endpoint;

    // Create a copy of the data
    let data = { ...json };

    // Extract symbol based on endpoint and data structure
    let symbol = extractSymbol(data, inputSymbol, endpoint);

    // Remove redundant fields from data
    delete data.endpoint;
    delete data.symbol;

    // Process data based on endpoint type using the appropriate processor
    if (dataProcessors[endpoint]) {
      data = dataProcessors[endpoint](data, symbol);

      // Normalize symbol format if needed
      if (endpoint === 'contract-details') {
        symbol = normalizeSymbol(symbol);
      }
    }

    // Return the standardized MongoDB document
    return {
      timestamp: Date.now(),
      symbol,
      endpoint,
      data
    };
  });
}

// n8n context
const inputSymbol = $json.symbol || 'UNKNOWN';

// If using Merge node (order known), set nodeMap accordingly
// The index corresponds to the position in the merged items array
const nodeMap = {
  0: 'price',
  1: 'candlestick',
  2: 'funding',
  3: 'contract-details',
  4: 'historical-funding',
  5: 'orderbook',
  6: 'trades'
};

// Process all items
const results = prepareMongoRecords($items(), inputSymbol, nodeMap);

// Return the processed results
return results;

