// Helper: EMA calculation (rest of the helpers are unchanged)
function calculateEMA(data, period) {
    const k = 2 / (period + 1);
    let emaArray = [];
    let emaPrev;

    data.forEach((price, i) => {
        if (i === 0) {
            emaPrev = price;
            emaArray.push(emaPrev);
        } else {
            let ema = price * k + emaPrev * (1 - k);
            emaArray.push(ema);
            emaPrev = ema;
        }
    });
    return emaArray;
}

// Helper: RSI calculation (using the corrected version from my previous answer)
function calculateRSI(data, period) {
    let rsiArray = new Array(data.length).fill(null);
    if (data.length <= period) return rsiArray;

    let gains = 0;
    let losses = 0;

    for (let i = 1; i <= period; i++) {
        const diff = data[i] - data[i - 1];
        if (diff >= 0) {
            gains += diff;
        } else {
            losses -= diff;
        }
    }

    let avgGain = gains / period;
    let avgLoss = losses / period;
    let rs = avgLoss === 0 ? (avgGain > 0 ? Infinity : 0) : avgGain / avgLoss;
    rsiArray[period] = 100 - 100 / (1 + rs);

    for (let j = period + 1; j < data.length; j++) {
        const delta = data[j] - data[j - 1];
        let gain = delta > 0 ? delta : 0;
        let loss = delta < 0 ? -delta : 0;

        avgGain = (avgGain * (period - 1) + gain) / period;
        avgLoss = (avgLoss * (period - 1) + loss) / period;

        rs = avgLoss === 0 ? (avgGain > 0 ? Infinity : 0) : avgGain / avgLoss;
        rsiArray[j] = 100 - 100 / (1 + rs);
    }

    return rsiArray;
}

// Extract close prices (assuming the candle objects have a 'close' property)
